import{_ as t,o as a,c as i,ai as n}from"./chunks/framework.LYGRWSbL.js";const f=JSON.parse(`{"title":"L'accusatif","description":"","frontmatter":{"prev":{"text":"Introduction Module 3","link":"/module-3-quotidien/"}},"headers":[],"relativePath":"module-3-quotidien/accusatif.md","filePath":"module-3-quotidien/accusatif.md","lastUpdated":1773320215000}`),s={name:"module-3-quotidien/accusatif.md"};function r(l,e,d,c,o,u){return a(),i("div",null,[...e[0]||(e[0]=[n('<h1 id="l-accusatif" tabindex="-1">L&#39;accusatif <a class="header-anchor" href="#l-accusatif" aria-label="Permalink to “L&#39;accusatif”">​</a></h1><p><strong>Prérequis :</strong> <a href="./../module-2-construire-une-phrase/negation.html">La négation</a></p><p><strong>Objectif :</strong> reconnaitre et utiliser l&#39;accusatif, le cas de l&#39;objet direct.</p><p>Le nominatif, vu au module 2, est le cas du sujet. L&#39;accusatif est le cas de l&#39;objet direct, ce qui subit l&#39;action.</p><h2 id="sujet-et-objet-direct" tabindex="-1">Sujet et objet direct <a class="header-anchor" href="#sujet-et-objet-direct" aria-label="Permalink to “Sujet et objet direct”">​</a></h2><p>Dans <em>&quot;Le chat mange la souris&quot;</em>, le chat fait l&#39;action (sujet, nominatif) et la souris la subit (objet direct, accusatif).</p><ul><li><em>Der Mann kauft <strong>einen Apfel</strong>.</em> - L&#39;homme achete une pomme.</li><li><em>Das Kind liebt <strong>die Katze</strong>.</em> - L&#39;enfant aime la chatte. (neutre grammatical → die Katze, féminin)</li><li><em>Ich lese <strong>das Buch</strong>.</em> - Je lis le livre.</li></ul><h2 id="ce-qui-change-a-l-accusatif" tabindex="-1">Ce qui change à l&#39;accusatif <a class="header-anchor" href="#ce-qui-change-a-l-accusatif" aria-label="Permalink to “Ce qui change à l&#39;accusatif”">​</a></h2><p>Bonne nouvelle : seul l&#39;article masculin change. Féminin, neutre et pluriel restent identiques au nominatif.</p><div class="mt-4 overflow-hidden rounded-xl border border-gray-200"><table class="w-full text-sm"><thead><tr class="bg-gray-50"><th class="p-3 text-left font-semibold text-gray-600">Cas</th><th class="p-3 text-center font-semibold text-blue-700">Masculin</th><th class="p-3 text-center font-semibold text-red-600">Féminin</th><th class="p-3 text-center font-semibold text-green-700">Neutre</th><th class="p-3 text-center font-semibold text-gray-700">Pluriel</th></tr></thead><tbody><tr class="border-t border-gray-100"><td class="p-3 font-medium text-gray-700">Nominatif (défini)</td><td class="p-3 text-center font-bold text-blue-700">der</td><td class="p-3 text-center font-bold text-red-600">die</td><td class="p-3 text-center font-bold text-green-700">das</td><td class="p-3 text-center font-bold text-gray-700">die</td></tr><tr class="border-t border-gray-100 bg-red-50"><td class="p-3 font-medium text-gray-700">Accusatif (défini)</td><td class="p-3 text-center font-bold text-blue-700">den</td><td class="p-3 text-center font-bold text-red-600">die</td><td class="p-3 text-center font-bold text-green-700">das</td><td class="p-3 text-center font-bold text-gray-700">die</td></tr><tr class="border-t border-gray-100 mt-2"><td class="p-3 font-medium text-gray-700">Nominatif (indefini)</td><td class="p-3 text-center font-bold text-blue-700">ein</td><td class="p-3 text-center font-bold text-red-600">eine</td><td class="p-3 text-center font-bold text-green-700">ein</td><td class="p-3 text-center text-gray-400">-</td></tr><tr class="border-t border-gray-100 bg-red-50"><td class="p-3 font-medium text-gray-700">Accusatif (indefini)</td><td class="p-3 text-center font-bold text-blue-700">einen</td><td class="p-3 text-center font-bold text-red-600">eine</td><td class="p-3 text-center font-bold text-green-700">ein</td><td class="p-3 text-center text-gray-400">-</td></tr></tbody></table></div><div class="tip custom-block"><p class="custom-block-title">Seul le masculin change</p><p><em>der</em> → <em>den</em> et <em>ein</em> → <em>einen</em>. C&#39;est le seul changement a retenir pour l&#39;accusatif. Féminin, neutre et pluriel sont identiques au nominatif.</p></div><h2 id="identifier-l-objet-direct" tabindex="-1">Identifier l&#39;objet direct <a class="header-anchor" href="#identifier-l-objet-direct" aria-label="Permalink to “Identifier l&#39;objet direct”">​</a></h2><p>L&#39;objet direct répond à la question &quot;quoi ?&quot; ou &quot;qui ?&quot; après le verbe :</p><ul><li><em>Ich kaufe <strong>einen Kaffee</strong>.</em> - J&#39;achete <strong>quoi</strong> ? Un cafe. → accusatif masculin</li><li><em>Er sieht <strong>die Frau</strong>.</em> - Il voit <strong>qui</strong> ? La femme. → accusatif féminin (inchange)</li><li><em>Wir brauchen <strong>das Auto</strong>.</em> - Nous avons besoin de <strong>quoi</strong> ? La voiture. → accusatif neutre (inchange)</li></ul><h2 id="kein-a-l-accusatif" tabindex="-1">kein à l&#39;accusatif <a class="header-anchor" href="#kein-a-l-accusatif" aria-label="Permalink to “kein à l&#39;accusatif”">​</a></h2><p><em>Kein</em> suit la même logique : seul le masculin change.</p><ul><li><em>Ich habe <strong>keinen</strong> Hunger.</em> - Je n&#39;ai pas faim. (masculin)</li><li><em>Er hat <strong>keine</strong> Zeit.</em> - Il n&#39;a pas le temps. (féminin, inchange)</li></ul><div class="warning custom-block"><p class="custom-block-title">Les pronoms changent aussi</p><p>Les pronoms personnels ont également des formes accusatif : <em>mich</em> (me), <em>dich</em> (te), <em>ihn</em> (le), <em>sie</em> (la), <em>es</em> (le/la neutre), <em>uns</em> (nous), <em>euch</em> (vous), <em>sie</em> (les). Ils seront detailles progressivement dans les prochaines lecons.</p></div><h2 id="verbes-qui-appellent-l-accusatif" tabindex="-1">Verbes qui appellent l&#39;accusatif <a class="header-anchor" href="#verbes-qui-appellent-l-accusatif" aria-label="Permalink to “Verbes qui appellent l&#39;accusatif”">​</a></h2><p>Ces verbes très courants prennent toujours un objet direct à l&#39;accusatif :</p><table tabindex="0"><thead><tr><th>Verbe</th><th>Sens</th><th>Exemple</th></tr></thead><tbody><tr><td>kaufen</td><td>acheter</td><td><em>Ich kaufe einen Apfel.</em></td></tr><tr><td>essen</td><td>manger</td><td><em>Er isst einen Kuchen.</em></td></tr><tr><td>trinken</td><td>boire</td><td><em>Sie trinkt einen Tee.</em></td></tr><tr><td>sehen</td><td>voir</td><td><em>Wir sehen den Film.</em></td></tr><tr><td>lesen</td><td>lire</td><td><em>Du liest das Buch.</em></td></tr><tr><td>haben</td><td>avoir</td><td><em>Ich habe einen Bruder.</em></td></tr><tr><td>brauchen</td><td>avoir besoin de</td><td><em>Ich brauche einen Stift.</em></td></tr></tbody></table>',21)])])}const h=t(s,[["render",r]]);export{f as __pageData,h as default};
